function ExplorerShell() {
  const { div, aside, main, header, span, nav } = tags;
  const [searchOpen, setSearchOpen] = createSignal(false);
  const sections = [
    { href: '#/foundations', icon: 'layers', label: 'Foundations' },
    { href: '#/components', icon: 'box', label: 'Components' },
    { href: '#/patterns', icon: 'layout', label: 'Patterns' },
    { href: '#/tokens', icon: 'palette', label: 'Tokens' }
  ];

  return div({ class: css('_grid _h[100vh]'), style: 'grid-template-columns:260px 1fr;grid-template-rows:auto 1fr' },
    aside({ class: css('_flex _col _gap1 _p3 _bgmuted _overflow[auto] _borderR'), style: 'grid-row:1/3' },
      Input({ placeholder: 'Search... (Cmd+K)', class: css('_mb3'), onfocus: () => setSearchOpen(true) }),
      nav({ class: css('_flex _col _gap1') },
        ...sections.map(s =>
          link({ href: s.href, class: css('_flex _aic _gap2 _p2 _px3 _r2 _textsm _fgfg _trans') },
            icon(s.icon), s.label
          )
        )
      )
    ),
    header({ class: css('_flex _aic _jcsb _px6 _py3 _borderB') },
      span({ class: css('_heading4') }, 'Explorer'),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'ghost', size: 'sm', onclick: () => setSearchOpen(true) }, icon('search'))
      )
    ),
    main({ class: css('_flex _col _gap4 _p6 _overflow[auto]') },
      div({ class: css('_p4 _fgmuted') }, 'Select a section from the sidebar to begin exploring.')
    )
  );
}
